## Step 2: Fully Deobfuscated Code

```javascript
// Constants
var TAU = 6.283;           // ≈ 2π (full circle in radians) ✓
var GOLDEN_RATIO = 1.618;  // ≈ φ (golden ratio) ✓
var SQRT_HALF = 0.707;     // ≈ 1/√2 ≈ √0.5 ✓

// Physics configuration
var config = {
    attraction: 4000,          // repulsion strength between nodes
    springCoeff: 0.004,        // spring stiffness coefficient
    amplification: 0.92,       // velocity damping factor (0.92 = 8% decay per tick)
    gravityPull: 0.0003,       // centering gravity strength
    streamCount: 40,           // max number of particles
    streamDecay: 0.04,         // particle drag/decay rate
    theta: 0.06               // camera smoothing interpolation factor
};

// Nodes
var nodes = [
    { id: 'hub',      label: 'Nexus',    r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',    label: 'Alpha',    r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',     label: 'Beta',     r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',    label: 'Gamma',    r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'delta',    label: 'Delta',    r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon',  label: 'Epsilon',  r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Spring connections (edges)
var edges = [
    { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
    { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
    { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
    { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera state
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particles
var particles = [];
var frameCount = 0;

// Find node by ID
function findNode(id) {
    for (var i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// Main physics step
function physicsStep() {
    // --- Node-node repulsion (Coulomb-like) ---
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var force = config.attraction / (dist * dist);
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;
            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // --- Spring forces (Hooke's law) ---
    for (var e = 0; e < edges.length; e++) {
        var nodeA = findNode(edges[e].a);
        var nodeB = findNode(edges[e].b);
        if (!nodeA || !nodeB) continue;
        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - edges[e].rest;
        var force = (edges[e].k || config.springCoeff) * displacement;
        nodeA.vx += (dx / dist) * force;
        nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force;
        nodeB.vy -= (dy / dist) * force;
    }

    // --- Integration: gravity, damping, position update ---
    for (var n = 0; n < nodes.length; n++) {
        // Centering gravity toward (400, 300)
        nodes[n].vx += (400 - nodes[n].x) * config.gravityPull;
        nodes[n].vy += (300 - nodes[n].y) * config.gravityPull;
        // Velocity damping
        nodes[n].vx *= config.amplification;
        nodes[n].vy *= config.amplification;
        // Position update
        nodes[n].x += nodes[n].vx;
        nodes[n].y += nodes[n].vy;
    }
}

// Spawn a particle from a random node
function spawnParticle() {
    if (particles.length >= config.streamCount) return;
    var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT_HALF;
    particles.push({
        x: sourceNode.x,
        y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + (Math.random() * GOLDEN_RATIO) * SQRT_HALF
    });
}

// Update particles
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];
        p.age++;
        // Apply drag
        p.vx *= (1 - config.streamDecay * 0.125);
        p.vy *= (1 - config.streamDecay * 0.125);
        // Move
        p.x += p.vx;
        p.y += p.vy;
        // Remove if expired
        if (p.age > p.maxAge) particles.splice(i, 1);
    }
}

// Smooth camera follow
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * config.theta;
    camera.y += (cameraTarget.y - camera.y) * config.theta;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * config.theta;
}

// Main loop tick
function tick() {
    physicsStep();
    updateParticles();
    updateCamera();
    if (frameCount % 3 === 0) spawnParticle();
    frameCount++;
}

setInterval(tick, 16); // ~60 FPS
```

## Step 3: Verification of Named Operations

| Name | Operation | Correct? |
|---|---|---|
| **`attraction`** (4000) | Used as numerator in `attraction / dist²` — inverse-square **repulsion** force | ⚠️ Name says "attraction" but it computes **repulsion** (pushes nodes apart). **Misnomer.** |
| **`springCoeff`** (0.004) | Multiplied by `(dist - rest)` — classic **Hooke's law** spring force | ✅ Matches |
| **`amplification`** (0.92) | Velocity is **multiplied** by 0.92 each frame — this is **damping**, not amplification | ⚠️ Name says "amplification" but value < 1 means it's **damping**. **Misnomer.** |
| **`gravityPull`** (0.0003) | Applied as `(center - pos) * gravityPull` — **centering gravity** | ✅ Matches |
| **`streamCount`** (40) | Caps `particles.length` — **max particle count** | ✅ Matches |
| **`streamDecay`** (0.04) | Multiplied into `(1 - decay * 0.125)` to slow particles — **drag/decay** | ✅ Matches |
| **`theta`** (0.06) | Used as linear interpolation factor for camera smoothing — **lerp coefficient** | ✅ Matches (theta as a smoothing parameter) |

### Summary

This is a **force-directed graph layout** with 6 nodes connected by springs, Coulomb-like repulsion, centering gravity, velocity damping, decorative particles, and a smoothly-interpolated camera — running at ~60 FPS.

Two config names are **misleading**: `attraction` actually computes repulsion, and `amplification` actually performs damping.
